mapper.insert:
INSERT INTO accounts (
  account_id, google_id, email, nick, profile_img_url
) VALUES (
  #{uuid}, #{googleId}, #{email}, #{nick}, #{profileImgUrl}
)

mapper.update:
UPDATE accounts
SET last_login = now()
WHERE account_id = #{uuid}

mapper.select:
SELECT CASE WHEN COUNT(*) > 0 THEN TRUE ELSE FALSE END
FROM accounts
WHERE nick = #{nick}

mapper.update:
UPDATE accounts
SET nick = #{nick}, updated_at = now()
WHERE account_id = #{uuid}

UPDATE accounts
SET profile_img_url = #{profileImgUrl}, updated_at = now()
WHERE account_id = #{uuid}

UPDATE accounts
SET nationality = #{nationality}, updated_at = now()
WHERE account_id = #{uuid}

UPDATE accounts
SET deletion_requested_at = #{deletionRequestedAt}
WHERE account_id = #{uuid}
